using namespace std;

int main(){
    int arr[100] = {2, 4, 6, 8, 10}; // Initial array
    int size = 5; // Current size of the array

    int positionToDelete = 2; // Index of the element to delete

    // Update the code to shift elements to fill the gap left by the deleted element
    for(int i=positionToDelete ; i<size-1 ; i++){
        arr[i] = arr[i+1];
    }

    size--;  // Update the size of the array


    // Print the updated array
    for (int i=0 ; i<size ; i++){
        cout<<arr[i]<<" ";
    }

    return 0;
}

code.C:
#include <stdio.h>

int main() {
    int arr[100];
    int size;

    // Read size of the array
    scanf("%d", &size);

    // Read array elements
    for (int i = 0; i < size; i++) {
        scanf("%d", &arr[i]);
    }

    int positionToDelete;
    // Read the index to delete (0-based)
    scanf("%d", &positionToDelete);

    // Shift elements to fill the gap
    for (int i = positionToDelete; i < size - 1; i++) {
        arr[i] = arr[i + 1];
    }

    size--; // Reduce size after deletion

    // Print updated array
    for (int i = 0; i < size; i++) {
        printf("%d ", arr[i]);
    }

    return 0;
}

